class SAMLParser:
    NAMESPACES = {
        'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
        'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
        'ds': 'http://www.w3.org/2000/09/xmldsig#',
    }

    def __init__(self, saml_response):
        self.saml_response = saml_response
        self.root = None
        self.assertion = None

    def parse(self):
        try:
            decoded = base64.b64decode(self.saml_response)
            self.root = ET.fromstring(decoded)
            return True
        except Exception as e:
            print(f"Error parsing SAML response: {e}")
            return False

    def validate_structure(self):
        if self.root is None:
            return False

        if self.root.tag != '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
            return False

        self.assertion = self.root.find('.//saml:Assertion', self.NAMESPACES)
        if self.assertion is None:
            return False

        subject = self.assertion.find('.//saml:Subject', self.NAMESPACES)
        if subject is None:
            return False

        name_id = subject.find('.//saml:NameID', self.NAMESPACES)
        if name_id is None:
            return False

        return True

    def validate_conditions(self):
        conditions = self.assertion.find('.//saml:Conditions', self.NAMESPACES)
        if conditions is None:
            return True

        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')

        now = datetime.utcnow()

        if not_before:
            not_before_dt = datetime.fromisoformat(not_before.replace('Z', '+00:00'))
            if now < not_before_dt.replace(tzinfo=None):
                return False

        if not_on_or_after:
            not_on_or_after_dt = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00'))
            if now >= not_on_or_after_dt.replace(tzinfo=None):
                return False

        return True

    def get_name_id(self):
        if self.assertion is None:
            return None

        subject = self.assertion.find('.//saml:Subject', self.NAMESPACES)
        if subject is None:
            return None

        name_id = subject.find('.//saml:NameID', self.NAMESPACES)
        if name_id is None:
            return None

        return name_id.text

    def get_attributes(self):
        if self.assertion is None:
            return {}

        attributes = {}
        attr_statement = self.assertion.find('.//saml:AttributeStatement', self.NAMESPACES)

        if attr_statement is None:
            return attributes

        for attr in attr_statement.findall('.//saml:Attribute', self.NAMESPACES):
            attr_name = attr.get('Name')
            attr_values = []

            for attr_value in attr.findall('.//saml:AttributeValue', self.NAMESPACES):
                if attr_value.text:
                    attr_values.append(attr_value.text)

            if attr_values:
                attributes[attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values

        return attributes

    def get_session_index(self):
        if self.assertion is None:
            return None

        authn_statement = self.assertion.find('.//saml:AuthnStatement', self.NAMESPACES)
        if authn_statement is None:
            return None

        return authn_statement.get('SessionIndex')


class SAMLServiceProvider:
    def __init__(self):
        self.parser = None

    def process_saml_response(self, saml_response):
        self.parser = SAMLParser(saml_response)

